// src/pages/Login.js
import React, { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';
import ThemeToggle from '../components/ThemeToggle';

/**
 * Login page component
 * - Uses CSS classes: auth-page, auth-card, auth-logo, form-group, form-label, form-input, btn-primary, error-text
 * - Reads theme from documentElement data-theme for logo selection (optional)
 * - Calls useAuth().login(email, password) — adapt if your hook uses different signature
 */
export default function Login() {
  const { login } = useAuth(); // expected: async function login(email, password)
  const navigate = useNavigate();

  const [email, setEmail] = useState(() => localStorage.getItem('suprs_remember_email') || '');
  const [password, setPassword] = useState('');
  const [remember, setRemember] = useState(() => !!localStorage.getItem('suprs_remember_email'));
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [pwScore, setPwScore] = useState(0);
  const [theme, setTheme] = useState(
    typeof document !== 'undefined' && document.documentElement.getAttribute('data-theme') === 'light'
      ? 'light'
      : 'dark'
  );

  useEffect(() => {
    const observer = new MutationObserver(() => {
      const t = document.documentElement.getAttribute('data-theme') === 'light' ? 'light' : 'dark';
      setTheme(t);
    });
    observer.observe(document.documentElement, { attributes: true, attributeFilter: ['data-theme'] });
    return () => observer.disconnect();
  }, []);

  useEffect(() => {
    // simple password score (0..4)
    const score = calculatePasswordScore(password);
    setPwScore(score);
  }, [password]);

  function calculatePasswordScore(pw) {
    if (!pw) return 0;
    let score = 0;
    if (pw.length >= 8) score++;
    if (/[A-Z]/.test(pw)) score++;
    if (/[0-9]/.test(pw)) score++;
    if (/[^A-Za-z0-9]/.test(pw)) score++;
    return score; // 0..4
  }

  function pwStrengthLabel(score) {
    if (score <= 1) return 'Weak';
    if (score === 2) return 'Okay';
    if (score === 3) return 'Good';
    return 'Strong';
  }

  async function handleSubmit(e) {
    e.preventDefault();
    setError('');
    if (!email || !password) {
      setError('Please enter both email and password.');
      return;
    }

    setLoading(true);
    try {
      // adapt if your useAuth expects different args (e.g., login({email, password}))
      await login(email.trim(), password);
      if (remember) localStorage.setItem('suprs_remember_email', email.trim());
      else localStorage.removeItem('suprs_remember_email');
      navigate('/dashboard');
    } catch (err) {
      // generic handling; replace with your backend error parsing
      setError(err?.message || 'Invalid credentials. Please try again.');
    } finally {
      setLoading(false);
    }
  }

  // PUBLIC_URL base (CRA sets this on build). Falls back to empty string in dev.
  const base = process.env.PUBLIC_URL || '';
  const themedLogo = `${base}/logo-${theme}.png`;
  const fallbackLogo = `${base}/logo.png`;

  return (
    <div className="auth-page" role="main">
      <div className="auth-card" aria-labelledby="login-heading">
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 8 }}>
          <img
            src={themedLogo}
            alt="SUPRS"
            className="auth-logo"
            onError={(e) => {
              // fallback to a single logo if themed logos are missing
              // ensure we only try fallback once to avoid an infinite loop
              const img = e.currentTarget;
              if (!img.dataset.fallbackTried) {
                img.dataset.fallbackTried = '1';
                img.src = fallbackLogo;
              }
            }}
          />
          <ThemeToggle />
        </div>

        <h2 id="login-heading" style={{ margin: '6px 0 8px' }}>Welcome back</h2>
        <p className="muted" style={{ marginBottom: 18 }}>Sign in to SUPRS Smart Parking System</p>

        <form onSubmit={handleSubmit} noValidate>
          <div className="form-group">
            <label className="form-label" htmlFor="email">Email</label>
            <input
              id="email"
              className="form-input"
              type="email"
              inputMode="email"
              autoComplete="email"
              placeholder="you@example.com"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              aria-required="true"
            />
          </div>

          <div className="form-group" style={{ marginBottom: 6 }}>
            <label className="form-label" htmlFor="password">Password</label>
            <div style={{ position: 'relative' }}>
              <input
                id="password"
                className="form-input"
                type={showPassword ? 'text' : 'password'}
                autoComplete="current-password"
                placeholder="Enter your password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                aria-required="true"
                style={{ paddingRight: 110 }}
              />
              <button
                type="button"
                aria-pressed={showPassword}
                onClick={() => setShowPassword((s) => !s)}
                className="btn-ghost"
                style={{
                  position: 'absolute',
                  right: 8,
                  top: 8,
                  height: 36,
                  padding: '0 10px',
                  borderRadius: 8,
                }}
              >
                {showPassword ? 'Hide' : 'Show'}
              </button>
            </div>

            <div
              aria-hidden="true"
              style={{ display: 'flex', alignItems: 'center', gap: 10, marginTop: 8 }}
            >
              <div style={{ flex: 1, height: 8, background: 'rgba(255,255,255,0.04)', borderRadius: 6, overflow: 'hidden' }}>
                <div
                  style={{
                    height: '100%',
                    width: `${(pwScore / 4) * 100}%`,
                    background:
                      pwScore <= 1
                        ? '#ef4444'
                        : pwScore === 2
                        ? '#f59e0b'
                        : pwScore === 3
                        ? '#10b981'
                        : 'linear-gradient(90deg,#10b981,#00d2ff)',
                    transition: 'width 180ms ease',
                  }}
                />
              </div>
              <div style={{ minWidth: 72, textAlign: 'right', fontSize: 13, color: 'var(--text-secondary)' }}>
                {password ? pwStrengthLabel(pwScore) : ''}
              </div>
            </div>
          </div>

          {error && <div role="alert" className="error-text" style={{ marginTop: 12 }}>{error}</div>}

          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: 18 }}>
            <label style={{ display: 'flex', gap: 8, alignItems: 'center', color: 'var(--text-secondary)' }}>
              <input
                type="checkbox"
                checked={remember}
                onChange={(e) => setRemember(e.target.checked)}
                aria-label="Remember my email"
              /> Remember me
            </label>

            <Link to="/forgot" style={{ color: 'var(--primary)', fontWeight: 700, textDecoration: 'none' }}>
              Forgot?
            </Link>
          </div>

          <button
            type="submit"
            className="btn-primary"
            disabled={loading}
            style={{ marginTop: 18 }}
          >
            {loading ? 'Signing in…' : 'Sign in'}
          </button>
        </form>

        <div style={{ marginTop: 18, textAlign: 'center', color: 'var(--text-secondary)' }}>
          Don't have an account?{' '}
          <Link to="/register" style={{ color: 'var(--primary)', fontWeight: 700 }}>
            Create one
          </Link>
        </div>
      </div>
    </div>
  );
}